using Bond;
using Bond.IO.Unsafe;
using Bond.Protocols;
using ShortDev.Microsoft.ConnectedDevices.Serialization;

namespace Tests;

public class ValueSetParseTest
{
    [Test]
    public Task Parse_ShouldSucceed()
    {
        var buffer = Convert.FromHexString("");
        CompactBinaryReader<InputBuffer> reader = new(new InputBuffer(buffer));

        var result = Deserialize<ValueSet>.From(reader);

        return Verify(result);
    }
}

